import { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext(null);

const BASE = "http://localhost:5000/api";

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const saved = localStorage.getItem('sam_user');
    if (saved) {
      try { setUser(JSON.parse(saved)); } catch {}
    }
    setLoading(false);
  }, []);

  const login = async (email, password) => {
    // Try backend first
    try {
      const res = await fetch(`${BASE}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
        signal: AbortSignal.timeout(3000), // 3 sec timeout
      });
      if (res.ok) {
        const data = await res.json();
        localStorage.setItem('sam_token', data.token);
        const u = {
          ...data.user,
          initials: data.user.name.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2),
        };
        localStorage.setItem('sam_user', JSON.stringify(u));
        setUser(u);
        return { ok: true };
      }
    } catch (e) {
      console.warn('Backend not reachable, using demo mode:', e.message);
    }

    // Fallback — demo mode (works without backend)
    const demoUser = {
      id: 1,
      name: 'Rahul Sharma',
      email: email || 'rahul@example.com',
      stream: 'Science (PCM)',
      phone: '+91 98765 43210',
      city: 'Delhi, India',
      linkedin: 'linkedin.com/in/rahulsharma',
      github: 'github.com/rahulsharma',
      initials: 'RS',
      is_admin: false,
      academics: {
        p10: 92, p12: 88, cgpa: 8.4,
        entrance_score: 145, entrance_exam: 'JEE Main',
        category: 'General', branch: 'Computer Science (CSE)',
        state: 'Delhi', extra: 'Sports (State Level)',
      },
      objective: 'Aspiring software engineer with strong foundation in CSE fundamentals.',
      skills: 'Python, C++, Java, React, Machine Learning, SQL, Git',
    };
    localStorage.setItem('sam_user', JSON.stringify(demoUser));
    setUser(demoUser);
    return { ok: true };
  };

  const signup = async (formData) => {
    try {
      const res = await fetch(`${BASE}/auth/signup`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
        signal: AbortSignal.timeout(3000),
      });
      if (res.ok) {
        const data = await res.json();
        localStorage.setItem('sam_token', data.token);
        const u = { ...data.user, initials: data.user.name.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2) };
        localStorage.setItem('sam_user', JSON.stringify(u));
        setUser(u);
        return { ok: true };
      }
    } catch (e) {
      console.warn('Backend not reachable:', e.message);
    }
    // Fallback
    const u = {
      id: 2, name: formData.name || 'New Student',
      email: formData.email, stream: formData.stream || 'Science (PCM)',
      initials: (formData.name || 'NS').split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2),
      academics: { p10: 0, p12: 0, cgpa: 0, entrance_score: 0, entrance_exam: 'JEE Main', category: 'General' },
    };
    localStorage.setItem('sam_user', JSON.stringify(u));
    setUser(u);
    return { ok: true };
  };

  const logout = () => {
    localStorage.removeItem('sam_token');
    localStorage.removeItem('sam_user');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, loading }}>
      {!loading && children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
